INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'dallas'), 'MF-3(A)', 'mf-3-a', 'Multifamily District', 'This district is intended for higher-density multifamily residential developments, allowing for a greater number of dwelling units per acre.', 90, 2, 6000, 60, 15, 20, 20, 'Tiered approach: no minimum for 0-20 dwelling units; 0.5 spaces per dwelling unit for 21-199 units; 1 space per dwelling unit for 200+ units.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
